urlset:

    {{ site.url }}/
    {{ date }}
    daily
    1.0

{% for page, title, desc, page_id in static_pages %}
{% if page_id != '404' %}

    {{ site.url }}/{{ page }}
    {{ date }}
    monthly
    0.5

{% endif %}
{% endfor %}
{% for cat in categories %}

    {{ site.url }}/{{ cat.slug }}.html
    {{ date }}
    weekly
    0.8

{% endfor %}
{% for article in articles %}

    {{ site.url }}/{{ article.slug }}.html
    {{ article.publish_date[:10] }}
    monthly
    0.7

{% endfor %}
